import{_ as a,c as t,o as i,ak as s,ao as n}from"./chunks/framework.B0TWM2iJ.js";const u=JSON.parse('{"title":"AireGlu Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireglu-v1-115-0.md","filePath":"aireblock-releases/aireglu-v1-115-0.md","lastUpdated":1775826979000}'),o={name:"aireblock-releases/aireglu-v1-115-0.md"};function r(l,e,d,p,c,h){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="aireglu-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+n+'"> AireGlu Release Notes</span> <a class="header-anchor" href="#aireglu-release-notes" aria-label="Permalink to “AireGlu Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.115.0<br><strong>Release Date:</strong> 10 March 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Endpoint Last Saved Timestamp and Sort Options (GLU-634)</li><li>Endpoint Dependency Graph — Beta (GLU-2832)</li></ul><h4 id="⚡-improvements" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements" aria-label="Permalink to “⚡ Improvements”">​</a></h4><ul><li>Wrapped Filter Paths in Endpoint Editor (GLU-2924)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Case-Insensitive Alphabetical Sorting for Endpoints (GLU-1965)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="endpoint-last-saved-timestamp-and-sort-options-glu-634" tabindex="-1">Endpoint Last Saved Timestamp and Sort Options (GLU-634) <a class="header-anchor" href="#endpoint-last-saved-timestamp-and-sort-options-glu-634" aria-label="Permalink to “Endpoint Last Saved Timestamp and Sort Options (GLU-634)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>The endpoints list now displays when each endpoint was last saved, giving users at-a-glance visibility of recent changes. A new sort dropdown allows endpoints to be ordered by most recently edited or alphabetically.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now instantly see when any endpoint was last updated, and quickly sort your endpoints list to bring the most recently changed ones to the top — making it much easier to track and manage ongoing work.</p></div><h4 id="endpoint-dependency-graph-—-beta-glu-2832" tabindex="-1">Endpoint Dependency Graph — Beta (GLU-2832) <a class="header-anchor" href="#endpoint-dependency-graph-—-beta-glu-2832" aria-label="Permalink to “Endpoint Dependency Graph — Beta (GLU-2832)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>A new dependency graph view is available in beta, allowing users to visualise the relationships between interconnected endpoints. Business transactions often span multiple endpoints, and this graph makes it easier to understand how they depend on one another.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>You can now explore a visual map of how your endpoints connect and rely on each other, making it simpler to understand complex workflows and spot the impact of any changes before you make them. As this feature is in beta, feedback is welcome.</p></div><h3 id="⚡-improvements-1" tabindex="-1">⚡ Improvements <a class="header-anchor" href="#⚡-improvements-1" aria-label="Permalink to “⚡ Improvements”">​</a></h3><hr><h4 id="wrapped-filter-paths-in-endpoint-editor-glu-2924" tabindex="-1">Wrapped Filter Paths in Endpoint Editor (GLU-2924) <a class="header-anchor" href="#wrapped-filter-paths-in-endpoint-editor-glu-2924" aria-label="Permalink to “Wrapped Filter Paths in Endpoint Editor (GLU-2924)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Long filter path values in the endpoint editor now wrap across multiple lines rather than overflowing or being truncated, improving readability for complex filter expressions.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Long filter paths are now fully visible in the editor without any need to scroll horizontally, making it easier to review and edit complex endpoint configurations.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="case-insensitive-alphabetical-sorting-for-endpoints-glu-1965" tabindex="-1">Case-Insensitive Alphabetical Sorting for Endpoints (GLU-1965) <a class="header-anchor" href="#case-insensitive-alphabetical-sorting-for-endpoints-glu-1965" aria-label="Permalink to “Case-Insensitive Alphabetical Sorting for Endpoints (GLU-1965)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Alphabetical sorting in the endpoints list previously treated uppercase and lowercase letters as separate groups, causing endpoints with upper-case names to be sorted separately from those beginning with lower-case letters. Sorting now correctly treats all letters as case-insensitive.</p></div>',28)])])}const b=a(o,[["render",r]]);export{u as __pageData,b as default};
